def transition(state, action):
    s = dict(state)
    name = action.get("name", "")
    params = action.get("params") or {}
    rails = s.get("rails", {})

    def attempt(rail):
        # One routing attempt on `rail`: always costs a fee and an attempt;
        # settles iff the rail can carry the amount, else the attempt fails.
        if rail not in rails:
            return
        cfg = rails[rail]
        s["attempts"] = s["attempts"] + 1
        s["fees_paid"] = s["fees_paid"] + cfg["fee"]
        s["rail"] = rail
        if s["amount"] <= cfg["limit"]:
            s["status"] = "settled"
            s["latency"] = s["latency"] + cfg["speed"]
            s["settled_amount"] = s["amount"]
        else:
            s["status"] = "failed"

    if name == "route":
        # Route a fresh or previously-failed payment on the chosen rail.
        if s["status"] in ("pending", "failed"):
            attempt(params.get("rail", "ach"))
    elif name == "retry":
        # Only after a rejection; re-route (default: a higher-limit fallback).
        if s["status"] == "failed":
            attempt(params.get("rail", s.get("rail") or "ach"))
    elif name == "reverse":
        # Only a settled payment can be reversed; the delivered amount is
        # clawed back, a reversal fee is charged, and paid routing fees are
        # NOT refunded.
        if s["status"] == "settled":
            cfg = rails.get(s.get("rail", ""), {})
            s["fees_paid"] = s["fees_paid"] + cfg.get("fee", 0)
            s["settled_amount"] = 0
            s["status"] = "reversed"

    return s

